289→        // note that there is no setting for openPgpProvider, because this will have to be set up together
290→        // with the actual provider after import anyways.
291→
292→        SETTINGS = Collections.unmodifiableMap(s);
293→
294→        Map<Integer, SettingsUpgrader> u = new HashMap<>();
