    private fun fixSpecialFolderSelection(account: ValidatedSettings.Account): ValidatedSettings.Account {
        val settings = account.settings.toMutableMap()
        var changed = false

        val folders = listOf("archive", "drafts", "sent", "spam", "trash")

        for (folder in folders) {
            val nameKey = "${folder}FolderName"
            val selectionKey = "${folder}FolderSelection"

            val folderName = settings[nameKey] as? String
            val selection = settings[selectionKey] as? SpecialFolderSelection

            if (folderName != null && selection == SpecialFolderSelection.AUTOMATIC) {
                settings[selectionKey] = SpecialFolderSelection.MANUAL
                changed = true
            }
        }

        return if (changed) {
            account.copy(settings = settings)
        } else {
            account
        }
    }
